// do executes an HTTP request. headerOverrides, when non-nil, override global
// RequiredHeaders for this specific request (used for per-endpoint API versioning).
func (c *Client) do(method, path string, params map[string]string, body any, headerOverrides map[string]string) (json.RawMessage, int, error) {
	targetURL := c.BaseURL + path

	var bodyBytes []byte
	if body != nil {
		b, err := json.Marshal(body)
		if err != nil {
			return nil, 0, fmt.Errorf("marshaling body: %w", err)
		}
		bodyBytes = b
	}

	// Resolve auth material before the dry-run branch so --dry-run can preview
	// exactly what would be sent. Uses only cached credentials; a token that
	// requires a network refresh will be re-fetched on the live request path,
	// not during dry-run.
	authHeader, err := c.authHeaderForPath(path)
	if err != nil {
		return nil, 0, err
	}

	// Build the request for dry-run display or actual execution
	if c.DryRun {
		return c.dryRun(method, targetURL, path, params, bodyBytes, headerOverrides, authHeader)
	}

	const maxRetries = 3
	var lastErr error

	for attempt := 0; attempt <= maxRetries; attempt++ {
		// Proactive rate limiting — wait before sending
		c.limiter.Wait()
		var bodyReader io.Reader
		if bodyBytes != nil {
			bodyReader = strings.NewReader(string(bodyBytes))
		}

		req, err := http.NewRequest(method, targetURL, bodyReader)
		if err != nil {
			return nil, 0, fmt.Errorf("creating request: %w", err)
		}
		if bodyBytes != nil {
			req.Header.Set("Content-Type", "application/json")
		}

		if params != nil {
			q := req.URL.Query()
			for k, v := range params {
				if v != "" {
					q.Set(k, v)
				}
			}
			req.URL.RawQuery = q.Encode()
		}

		if authHeader != "" {
			req.Header.Set("Authorization", authHeader)
		}
		req.Header.Set("X-locale", "en_US")
		// Per-endpoint header overrides (e.g., different API version per resource)
		for k, v := range headerOverrides {
			req.Header.Set(k, v)
		}
		req.Header.Set("User-Agent", "fedex-pp-cli/0.1.0")

		resp, err := c.HTTPClient.Do(req)
		if err != nil {
			lastErr = fmt.Errorf("%s %s: %w", method, path, err)
			continue
		}

		respBody, err := io.ReadAll(resp.Body)
		resp.Body.Close()
		if err != nil {
			return nil, 0, fmt.Errorf("reading response: %w", err)
		}
		respBody = sanitizeJSONResponse(respBody)

		// Success
		if resp.StatusCode < 400 {
			c.limiter.OnSuccess()
			// Cache-invalidate on successful non-GET requests. The !c.DryRun guard
			// is structurally redundant (dry-run short-circuits before the retry
			// loop) but defends against future refactors.
			if method != http.MethodGet && !c.DryRun {
				c.invalidateCache()
			}
			return json.RawMessage(respBody), resp.StatusCode, nil
		}

		apiErr := &APIError{
			Method:     method,
			Path:       path,
			StatusCode: resp.StatusCode,
			Body:       truncateBody(respBody),
		}

		// Rate limited - adjust adaptive limiter and retry
		if resp.StatusCode == 429 && attempt < maxRetries {
			c.limiter.OnRateLimit()
			wait := cliutil.RetryAfter(resp)
			fmt.Fprintf(os.Stderr, "rate limited, waiting %s (attempt %d/%d, rate adjusted to %.1f req/s)\n", wait, attempt+1, maxRetries, c.limiter.Rate())
			time.Sleep(wait)
			lastErr = apiErr
			continue
		}

		// Server error - retry with backoff
		if resp.StatusCode >= 500 && attempt < maxRetries {
			wait := time.Duration(math.Pow(2, float64(attempt))) * time.Second
			fmt.Fprintf(os.Stderr, "server error %d, retrying in %s (attempt %d/%d)\n", resp.StatusCode, wait, attempt+1, maxRetries)
			time.Sleep(wait)
			lastErr = apiErr
			continue
		}

		// Client error or retries exhausted - return the error
		return nil, resp.StatusCode, apiErr
	}

	return nil, 0, lastErr
}

// dryRun prints the outgoing request exactly as the live path would send it,
// using the auth material already resolved in `do()`. Never triggers a network
// call — the caller is responsible for passing cached auth material only.
func (c *Client) dryRun(method, targetURL, path string, params map[string]string, body []byte, headerOverrides map[string]string, authHeader string) (json.RawMessage, int, error) {
	fmt.Fprintf(os.Stderr, "%s %s\n", method, targetURL)
	queryPrinted := false
	if params != nil {
		keys := make([]string, 0, len(params))
		for k := range params {
			if params[k] != "" {
				keys = append(keys, k)
			}
		}
		sort.Strings(keys)
		for _, k := range keys {
			sep := "?"
			if queryPrinted {
				sep = "&"
			}
			fmt.Fprintf(os.Stderr, "  %s%s=%s\n", sep, k, params[k])
			queryPrinted = true
		}
	}
	_ = queryPrinted
	if body != nil {
		var pretty json.RawMessage
		if json.Unmarshal(body, &pretty) == nil {
			enc := json.NewEncoder(os.Stderr)
			enc.SetIndent("  ", "  ")
			fmt.Fprintf(os.Stderr, "  Body:\n")
			enc.Encode(pretty)
		}
	}
	if authHeader != "" {
		fmt.Fprintf(os.Stderr, "  %s: %s\n", "Authorization", maskToken(authHeader))
	}
	fmt.Fprintf(os.Stderr, "\n(dry run - no request sent)\n")
	return json.RawMessage(`{"dry_run": true}`), 0, nil
}

func (c *Client) ConfiguredTimeout() time.Duration {
	if c.HTTPClient != nil && c.HTTPClient.Timeout > 0 {
		return c.HTTPClient.Timeout
	}
	return 30 * time.Second
}

// FedEx uses OAuth2 client_credentials with no refresh token — the only
// way to extend a session is to re-mint via the same grant. authHeader
// refreshes proactively when the cached token will expire within the
// safety window, or when no token is cached but env-var credentials are
// available (first-call mint without a separate `auth login` step).
//
// As of Oct 2023 FedEx requires Track API in its own project, so paths
// under /track/ get routed through a separate credential pair when
// configured. authHeaderForPath dispatches to the right pair.
func (c *Client) authHeader() (string, error) {
	return c.authHeaderForPath("")
}

func (c *Client) authHeaderForPath(path string) (string, error) {
	if c.Config == nil {
		return "", nil
	}
	if isTrackPath(path) && trackCredsConfigured(c.Config) {
		// Track-only project. Mint into the Track token slot.
		if needsTrackTokenMint(c.Config) {
			id, secret := resolveTrackCredentials(c.Config)
			if id != "" && secret != "" {
				if err := c.mintTrackToken(id, secret); err != nil {
					return "", err
				}
			}
		}
		return c.Config.AuthHeaderForPath(path), nil
	}
	// Default pair (Ship/Rate/Address/Pickup/Locations/etc.).
	if needsTokenMint(c.Config) {
		clientID, clientSecret := resolveOAuthCredentials(c.Config)
		if clientID != "" && clientSecret != "" {
			if err := c.mintClientCredentialsToken(clientID, clientSecret); err != nil {
				return "", err
			}
		}
	}
	return c.Config.AuthHeaderForPath(path), nil
}

// isTrackPath duplicates the config-package helper because the client must
// not depend on internal package layout (the templates differ across CLIs);
// kept in lockstep here.
func isTrackPath(path string) bool {
	return strings.HasPrefix(strings.TrimSpace(path), "/track/")
}

func trackCredsConfigured(cfg *config.Config) bool {
	return cfg.TrackClientID != "" || cfg.TrackApiKey != "" || os.Getenv("FEDEX_TRACK_API_KEY") != ""
}

// needsTokenMint returns true when the cached token is missing or will
// expire within the next 60 seconds. The 60-second safety window avoids
// in-flight requests racing the expiry boundary.
func needsTokenMint(cfg *config.Config) bool {
	if cfg.AccessToken == "" {
		return true
	}
	if cfg.TokenExpiry.IsZero() {
		return false
	}
	return time.Until(cfg.TokenExpiry) < 60*time.Second
}

func needsTrackTokenMint(cfg *config.Config) bool {
	if cfg.TrackAccessToken == "" {
		return true
	}
	if cfg.TrackTokenExpiry.IsZero() {
		return false
	}
	return time.Until(cfg.TrackTokenExpiry) < 60*time.Second
}

// resolveOAuthCredentials prefers what was passed to `auth login` (cached
// in config) and falls back to environment variables so first-time users
// can ship without a separate login step.
func resolveOAuthCredentials(cfg *config.Config) (string, string) {
	id := cfg.ClientID
	secret := cfg.ClientSecret
	if id == "" {
		id = os.Getenv("FEDEX_API_KEY")
	}
	if secret == "" {
		secret = os.Getenv("FEDEX_SECRET_KEY")
	}
	return id, secret
}

func resolveTrackCredentials(cfg *config.Config) (string, string) {
	id := cfg.TrackClientID
	secret := cfg.TrackClientSecret
	if id == "" {
		id = os.Getenv("FEDEX_TRACK_API_KEY")
	}
	if secret == "" {
		secret = os.Getenv("FEDEX_TRACK_SECRET_KEY")
	}
	return id, secret
}

func (c *Client) mintTrackToken(clientID, clientSecret string) error {
	tokenURL := strings.TrimRight(c.BaseURL, "/") + "/oauth/token"
	form := url.Values{
		"grant_type":    {"client_credentials"},
		"client_id":     {clientID},
		"client_secret": {clientSecret},
	}
	req, err := http.NewRequest(http.MethodPost, tokenURL, strings.NewReader(form.Encode()))
	if err != nil {
		return fmt.Errorf("building track-token request: %w", err)
	}
	req.Header.Set("Content-Type", "application/x-www-form-urlencoded")
	resp, err := c.HTTPClient.Do(req)
	if err != nil {
		return fmt.Errorf("calling FedEx track token endpoint: %w", err)
	}
	defer resp.Body.Close()
	body, _ := io.ReadAll(resp.Body)
	if resp.StatusCode >= 400 {
		return fmt.Errorf("FedEx track auth: HTTP %d: %s", resp.StatusCode, truncateBody(body))
	}
	var tokenResp struct {
		AccessToken string `json:"access_token"`
		ExpiresIn   int    `json:"expires_in"`
	}
	if err := json.Unmarshal(body, &tokenResp); err != nil {
		return fmt.Errorf("parsing track token response: %w", err)
	}
	if tokenResp.AccessToken == "" {
		return fmt.Errorf("FedEx track auth: response missing access_token")
	}
	expiry := time.Now().Add(time.Duration(tokenResp.ExpiresIn) * time.Second)
	if err := c.Config.SaveTrackTokens(clientID, clientSecret, tokenResp.AccessToken, expiry); err != nil {
		return fmt.Errorf("saving track token: %w", err)
	}
	return nil
}

func (c *Client) mintClientCredentialsToken(clientID, clientSecret string) error {
	tokenURL := strings.TrimRight(c.BaseURL, "/") + "/oauth/token"

	form := url.Values{
		"grant_type":    {"client_credentials"},
		"client_id":     {clientID},
		"client_secret": {clientSecret},
	}

	req, err := http.NewRequest(http.MethodPost, tokenURL, strings.NewReader(form.Encode()))
	if err != nil {
		return fmt.Errorf("building token request: %w", err)
	}
	req.Header.Set("Content-Type", "application/x-www-form-urlencoded")

	resp, err := c.HTTPClient.Do(req)
	if err != nil {
		return fmt.Errorf("calling FedEx token endpoint: %w", err)
	}
	defer resp.Body.Close()

	body, _ := io.ReadAll(resp.Body)
	if resp.StatusCode >= 400 {
		return fmt.Errorf("FedEx auth: HTTP %d: %s", resp.StatusCode, truncateBody(body))
	}

	var tokenResp struct {
		AccessToken string `json:"access_token"`
		ExpiresIn   int    `json:"expires_in"`
	}
	if err := json.Unmarshal(body, &tokenResp); err != nil {
		return fmt.Errorf("parsing FedEx token response: %w", err)
	}
	if tokenResp.AccessToken == "" {
		return fmt.Errorf("FedEx auth: response missing access_token")
	}

	expiry := time.Now().Add(time.Duration(tokenResp.ExpiresIn) * time.Second)
	c.Config.AuthHeaderVal = "" // force AuthHeader() to use AccessToken path
	if err := c.Config.SaveTokens(clientID, clientSecret, tokenResp.AccessToken, "", expiry); err != nil {
		return fmt.Errorf("saving FedEx token: %w", err)
	}
	return nil
}

// sanitizeJSONResponse strips known JSONP/XSSI prefixes and UTF-8 BOM from
// response bodies so that downstream JSON parsing succeeds. For clean JSON
// responses these checks are no-ops.
func sanitizeJSONResponse(body []byte) []byte {
	// UTF-8 BOM
	body = bytes.TrimPrefix(body, []byte("\xEF\xBB\xBF"))

	// JSONP/XSSI prefixes, ordered longest-first where prefixes overlap
	prefixes := [][]byte{
		[]byte(")]}'\n"),
		[]byte(")]}'"),
		[]byte("{}&&"),
		[]byte("for(;;);"),
		[]byte("while(1);"),
	}
	for _, p := range prefixes {
		if bytes.HasPrefix(body, p) {
			body = bytes.TrimPrefix(body, p)
			body = bytes.TrimLeft(body, " \t\r\n")
			break
		}
	}
	return body
}

// maskToken redacts all but the last 4 characters of a token for safe display.
func maskToken(token string) string {
	if token == "" {
		return ""
	}
	if len(token) <= 4 {
		return "****"
	}
	return "****" + token[len(token)-4:]
}

func truncateBody(b []byte) string {
	s := string(b)
	if len(s) > 200 {
		return s[:200] + "..."
	}
	return s
}
